import React, { useState } from 'react';
import ApplicationForm from '../components/ApplicationForm';
import { hackathons } from '../data/appData';

export default function Competitions() {
  const [searchTerm, setSearchTerm] = useState('');
  
  // Стан для модального вікна (якщо null - закрито, якщо об'єкт - відкрито)
  const [selectedHackathon, setSelectedHackathon] = useState(null);

  // Фільтруємо хакатони
  const filteredHackathons = hackathons.filter(h =>
    h.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    h.topic.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // Функція для закриття модалки
  const closeModal = () => setSelectedHackathon(null);

  return (
    <main>
      <section>
        <h1>Доступні змагання</h1>
        <p>Оберіть хакатон, ознайомтеся з правилами та критеріями оцінювання, і подавайте заявку!</p>

        {/* Поле пошуку */}
        <div style={{ marginBottom: '24px' }}>
          <input
            type="text"
            placeholder="Пошук за назвою або темою (наприклад, AI)..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            style={{
              padding: '10px 16px',
              width: '100%',
              maxWidth: '400px',
              borderRadius: '8px',
              border: '1px solid #ccc',
              fontSize: '1rem'
            }}
          />
        </div>

        {/* Сітка змагань */}
        <div className="feature-grid">
          {filteredHackathons.length === 0 ? (
            <p>За вашим запитом нічого не знайдено 😔</p>
          ) : (
            filteredHackathons.map((h) => (
              <article key={h.slug} className="feature-card" style={{ display: 'flex', flexDirection: 'column' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '8px' }}>
                  <h3 style={{ margin: 0 }}>{h.title}</h3>
                  <span className="status status-progress" style={{ fontSize: '0.75rem', whiteSpace: 'nowrap', marginLeft: '10px' }}>
                    {h.topic}
                  </span>
                </div>
                
                <p style={{ color: '#d93025', fontWeight: 'bold', fontSize: '0.9rem', margin: '0 0 12px 0' }}>
                  ⏳ Дедлайн: {h.deadlineLabel}
                </p>
                <p style={{ flexGrow: 1 }}>{h.short}</p>

                {/* Кнопка, яка відкриває модалку */}
                <button 
                  onClick={() => setSelectedHackathon(h)} 
                  className="btn-primary"
                  style={{ marginTop: '16px', alignSelf: 'flex-start' }}
                >
                  Детальніше
                </button>
              </article>
            ))
          )}
        </div>
      </section>

      <section className="application-panel" style={{ marginTop: '40px' }}>
        <h2>Подати заявку на змагання</h2>
        <p>Заповніть форму нижче. Після відправки ви зможете керувати своєю заявкою на сторінці "Мої проєкти".</p>
        <ApplicationForm hackathons={hackathons} />
      </section>

      {/* МОДАЛЬНЕ ВІКНО */}
      {selectedHackathon && (
        <div 
          style={{
            position: 'fixed', top: 0, left: 0, right: 0, bottom: 0,
            backgroundColor: 'rgba(0, 0, 0, 0.6)', // Напівпрозорий фон
            display: 'flex', justifyContent: 'center', alignItems: 'center',
            zIndex: 1000, padding: '20px'
          }} 
          onClick={closeModal} // Клік по темному фону закриває модалку
        >
          {/* Контент модалки */}
          <div 
            style={{
              backgroundColor: '#fff', padding: '30px', borderRadius: '12px',
              maxWidth: '600px', width: '100%', maxHeight: '90vh', overflowY: 'auto',
              position: 'relative', boxShadow: '0 10px 25px rgba(0,0,0,0.2)'
            }} 
            onClick={(e) => e.stopPropagation()} // Щоб клік всередині білого блоку не закривав модалку
          >
            {/* Кнопка-хрестик */}
            <button 
              onClick={closeModal} 
              style={{
                position: 'absolute', top: '15px', right: '15px',
                background: 'none', border: 'none', fontSize: '1.5rem', 
                cursor: 'pointer', color: '#666'
              }}
            >
              &times;
            </button>

            <h2 style={{ marginTop: 0, color: '#1a73e8' }}>{selectedHackathon.title}</h2>
            <p><strong>Опис:</strong> {selectedHackathon.details.description}</p>
            
            <strong style={{ display: 'block', marginTop: '16px' }}>📋 Правила:</strong>
            <ul style={{ paddingLeft: '20px', margin: '8px 0' }}>
              {selectedHackathon.details.rules.map((rule, i) => <li key={i}>{rule}</li>)}
            </ul>
            
            <strong style={{ display: 'block', marginTop: '16px' }}>🎯 Критерії:</strong>
            <ul style={{ paddingLeft: '20px', margin: '8px 0' }}>
              {selectedHackathon.details.criteria.map((crit, i) => <li key={i}>{crit}</li>)}
            </ul>
            
            <strong style={{ display: 'block', marginTop: '16px' }}>🏆 Призи:</strong>
            <ul style={{ paddingLeft: '20px', margin: '8px 0' }}>
              {selectedHackathon.details.prizes.map((prize, i) => <li key={i}>{prize}</li>)}
            </ul>

            <button 
              onClick={closeModal} 
              className="btn-secondary" 
              style={{ marginTop: '20px', width: '100%' }}
            >
              Зрозуміло, закрити
            </button>
          </div>
        </div>
      )}
    </main>
  );
}
